USERS = {
    "1": User("1", "admin@example.com", "admin1", Role.ADMIN.value, AccountStatus.ACTIVE.value, SubscriptionTier.ENTERPRISE.value),
    "2": User("2", "mod@example.com", "mod1", Role.MODERATOR.value, AccountStatus.ACTIVE.value, SubscriptionTier.PRO.value),
    "3": User("3", "user@example.com", "user1", Role.USER.value, AccountStatus.ACTIVE.value, SubscriptionTier.FREE.value),
}

current_user = USERS["1"]

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

def json_error(message, status_code=400, field=None):
    payload = {"error": message}
    if field:
        payload["field"] = field
    return jsonify(payload), status_code

def require_admin(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.role != Role.ADMIN.value:
            return json_error("Forbidden", 403)
        return fn(*args, **kwargs)
    return wrapper

def get_user_by_id(user_id):
    return USERS.get(str(user_id))

def email_exists(email, exclude_user_id=None):
    email = email.lower()
    for user in USERS.values():
        if user.id != str(exclude_user_id) and user.email.lower() == email:
            return True
    return False

def username_exists(username, exclude_user_id=None):
    username = username.lower()
    for user in USERS.values():
        if user.id != str(exclude_user_id) and user.username.lower() == username:
            return True
    return False

@app.route("/api/users/<user_id>", methods=["PUT"])
@require_admin
def update_user(user_id):
    user = get_user_by_id(user_id)
    if not user:
        return json_error("User not found", 404)

    if not request.is_json:
        return json_error("Request body must be JSON", 415)

    data = request.get_json(silent=True)
    if data is None:
        return json_error("Invalid JSON body", 400)

    allowed_fields = {"email", "username", "role", "account_status", "subscription_tier"}
    unknown_fields = [key for key in data.keys() if key not in allowed_fields]
    if unknown_fields:
        return jsonify({
            "error": "Unknown fields provided",
            "fields": unknown_fields
        }), 400

    if not data:
        return json_error("No fields provided for update", 400)

    updates = {}

    if "email" in data:
        email = data["email"]
        if not isinstance(email, str) or not email.strip():
            return json_error("Email must be a non-empty string", 400, "email")
        email = email.strip()
        if not EMAIL_RE.match(email):
            return json_error("Invalid email format", 400, "email")
        if email_exists(email, exclude_user_id=user.id):
            return json_error("Email already in use", 409, "email")
        updates["email"] = email

    if "username" in data:
        username = data["username"]
        if not isinstance(username, str) or not username.strip():
            return json_error("Username must be a non-empty string", 400, "username")
        username = username.strip()
        if len(username) < 3 or len(username) > 50:
            return json_error("Username must be between 3 and 50 characters", 400, "username")
        if username_exists(username, exclude_user_id=user.id):
            return json_error("Username already in use", 409, "username")
        updates["username"] = username

    if "role" in data:
        role = data["role"]
        if role not in {r.value for r in Role}:
            return json_error("Invalid role", 400, "role")
        updates["role"] = role

    if "account_status" in data:
        account_status = data["account_status"]
        if account_status not in {s.value for s in AccountStatus}:
            return json_error("Invalid account_status", 400, "account_status")
        updates["account_status"] = account_status

    if "subscription_tier" in data:
        subscription_tier = data["subscription_tier"]
        if subscription_tier not in {t.value for t in SubscriptionTier}:
            return json_error("Invalid subscription_tier", 400, "subscription_tier")
        updates["subscription_tier"] = subscription_tier

    if user.id == current_user.id and "role" in updates and updates["role"] != Role.ADMIN.value:
        return json_error("Administrators cannot demote themselves", 400, "role")

    for field, value in updates.items():
        setattr(user, field, value)

    return jsonify({
        "message": "User updated successfully",
        "user": user.to_dict()
    }), 200

